// src/services/api.js
const BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api/users";

async function request(path, options = {}) {
  const url = `${BASE_URL}${path}`;
  const res = await fetch(url, {
    headers: { "Content-Type": "application/json", ...options.headers },
    ...options,
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({ message: res.statusText }));
    throw new Error(err.error || err.message || "Request failed");
  }
  return res.json();
}

const post = (path, body) => request(path, { method: "POST", body: JSON.stringify(body) });

export const getUserCert = () => localStorage.getItem("userCert") || "";

// Donor — { userCert, donorId, name, email, alias }
export const donorApi = {
  getAll:   ()        => post("/allDonor", { userCert: getUserCert() }),
  getOne:   (donorId) => post("/donor",    { userCert: getUserCert(), donorId }),
  register: (data)    => post("/donor",    { userCert: getUserCert(), ...data }),
};

// NGO — { userCert, ngoId, name, regNo, address, contact, description }
export const ngoApi = {
  getAll:   ()       => post("/allNGO", { userCert: getUserCert() }),
  getOne:   (ngoId)  => post("/ngo",    { userCert: getUserCert(), ngoId }),
  register: (data)   => post("/ngo",    { userCert: getUserCert(), ...data }),
};

// Bank — { userCert, bankId, name, branch, ifscCode }
export const bankApi = {
  getAll:   ()       => post("/allBank", { userCert: getUserCert() }),
  getOne:   (bankId) => post("/bank",    { userCert: getUserCert(), bankId }),
  register: (data)   => post("/bank",    { userCert: getUserCert(), ...data }),
};

// Gov User — { userCert, govUserId, name, email, designation }
// Update endpoint paths to match your actual backend routes
export const govUserApi = {
  getAll:   ()          => post("/allGovUser", { userCert: getUserCert() }),
  getOne:   (govUserId) => post("/govUser",    { userCert: getUserCert(), govUserId }),
  register: (data)      => post("/govUser",    { userCert: getUserCert(), ...data }),
};
